PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE trades (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                timestamp TEXT NOT NULL DEFAULT (datetime('now')),
                symbol TEXT NOT NULL,
                side TEXT NOT NULL,
                qty REAL NOT NULL,
                price REAL,
                order_id TEXT,
                signal_type TEXT,
                strategy TEXT,
                reason TEXT,
                ai_reasoning TEXT,
                ai_confidence REAL,
                stop_loss REAL,
                take_profit REAL,
                status TEXT DEFAULT 'open',
                pnl REAL,
                decision_price REAL,
                fill_price REAL,
                slippage_pct REAL
            , max_favorable_excursion REAL, protective_stop_order_id TEXT, protective_tp_order_id TEXT, protective_trailing_order_id TEXT, occ_symbol TEXT, option_strategy TEXT, expiry TEXT, strike REAL, predicted_slippage_bps REAL, adv_at_decision REAL, data_quality TEXT);
COMMIT;
